import React from 'react'
import style from './style.module.css'

function Location() {
    return (
        <div className={style.locationContainer}>
            <p>Welcome!</p>

            <p>We warmly invite you to celebrate our wedding day with us in the Police Mosque (Masjid El Shorta), New cairo. We look forward to sharing this unforgettable moment with you.</p>
        </div>
    )
}

export default Location
